        {

            if(vis3[i]==1){vis2[x][i]=1;vis2[i][x]=1;}

            if(dist[i]<ma[x][i])

            {

                flag=1;

            }

        }

    }

   //printf("\n");

}

int main()

{

    scanf("%lld",&n);

    for(i=1; i<=n; i++)

    {

        for(j=1; j<=n; j++)

        {

            scanf("%lld",&ma[i][j]);

        }



    }

    ans=0;

    flag=0;



    for(l=1; l<=n; l++)

    {

        dijkstra(l);

        if(flag==1) break;

    }

